const body = $input.item.json.body || $input.item.json;

// Elementor form format (from landing page via lead-intake webhook)
if (body['form[id]'] !== undefined || body.form_id !== undefined) {
  let phone = body['fields[email][value]'] || 
              body['fields[phone][value]'] || 
              body['fields[field_629a3b0][value]'] || '';
  let name = body['fields[name][value]'] || '';
  let email = body['fields[field_629a3b0][value]'] || 
              body['fields[email][value]'] || '';

  for (const key of Object.keys(body)) {
    if (key.includes('[value]')) {
      const val = body[key];
      if (typeof val === 'string' && (val.startsWith('05') || val.startsWith('972'))) {
        phone = val;
      }
    }
  }

  phone = phone.replace(/[\s\-\(\)]/g, '');
  if (phone.startsWith('0')) phone = '972' + phone.substring(1);
  if (phone.startsWith('+')) phone = phone.substring(1);

  return {
    json: {
      skip: false,
      isFormSubmission: true,
      phone: phone,
      name: name,
      email: email,
      messageText: 'START',
      isNewLead: true
    }
  };
}

// Twilio WhatsApp webhook format
// Twilio sends: From=whatsapp:+972..., Body=message text, ProfileName=name
const twilioFrom = body.From || '';
const twilioBody = body.Body || '';
const twilioName = body.ProfileName || '';

if (twilioFrom.includes('whatsapp:')) {
  let phone = twilioFrom.replace('whatsapp:', '').replace('+', '').trim();

  return {
    json: {
      skip: false,
      isFormSubmission: false,
      phone: phone,
      name: twilioName,
      email: '',
      messageText: twilioBody,
      isNewLead: false
    }
  };
}

// WATI webhook format (fallback)
const wapiPhone = body.waId || body.from || '';
const wapiMessage = body.text?.body || body.text || body.body || '';

if (wapiPhone && wapiMessage) {
  let phone = wapiPhone.replace(/[\s\-\(\)]/g, '');
  if (phone.startsWith('+')) phone = phone.substring(1);

  return {
    json: {
      skip: false,
      isFormSubmission: false,
      phone: phone,
      name: body.senderName || '',
      email: '',
      messageText: wapiMessage,
      isNewLead: false
    }
  };
}

// 360dialog format (fallback)
const contacts = body.contacts || [];
const messages = body.messages || [];

if (!messages.length) {
  return { json: { skip: true } };
}

const msg = messages[0];
const contact = contacts[0] || {};

let phone = msg.from || '';
phone = phone.replace(/[\s\-\(\)]/g, '');
if (phone.startsWith('+')) phone = phone.substring(1);

return {
  json: {
    skip: false,
    isFormSubmission: false,
    phone: phone,
    name: contact.profile?.name || '',
    email: '',
    messageText: msg.text?.body || msg.button?.text || '',
    isNewLead: false
  }
};

const reply = $('🔍 פענוח Twilio').item.json;
const rows = $input.all();
const session = rows[0]?.json || {};

const TEMPLATES = {
  'ASK_FAMILIARITY': 'HXe1528eca7b4f8c26071a6aecb72d6b37',
  'ASK_EXPERIENCE': 'HX80d4d5e5dad532bb527356f671fab535',
  'ASK_UNDERSTANDING': 'HX6f09b6c7d6cf1c165b59f3304d1b0139',
  'ASK_HOURS': 'HXe3569a7041bfe591b19ed0f4ce0464bf',
  'ASK_BUDGET': 'HXa8f28b04902f5001977d2b68e776327c',
  'ASK_PARENTS': 'HXb899ed181841811b051ea347cf94ffd9',
  'ASK_MEETING_INTRO': 'HX71be15d7e3eda960bcc31b16ab0be084',
  'ASK_AVAILABILITY': 'HXbbe65873fa6c5d1a8f07ef7827ab7477',
};

if (!session.phone && !reply.isFormSubmission && !reply.isNewLead) {
  return { json: { _skip: true, phone: reply.phone } };
}

const phone = reply.phone || session.phone;
const message = reply.messageText || '';
const currentState = session.state || 'WAIT_CONFIRM';
let score = parseFloat(session.score || 0);
let answers = {};
try {
  const rawAns = session.answers || '{}';
  if (typeof rawAns === 'object' && rawAns !== null) {
    answers = rawAns;
  } else if (typeof rawAns === 'string') {
    answers = JSON.parse(rawAns);
  }
} catch(e) { answers = {}; }
let has_experience = session.has_experience === true || session.has_experience === 'true';

let state = currentState;
let responseMsg = '';
let contentSid = null;
let _done = false;
let _disqualified = false;
let _skip = false;
let _optedOut = false;

let lead_type = session.lead_type || 'pending';
let status = session.status || 'in_progress';
let age = session.age || null;
let availability = session.availability || null;
let meeting_type = session.meeting_type || null;
let completed_at = null;

const msg = message.toLowerCase().trim();

function getChoice(text) {
  const t = text.trim();
  if (/^[1-4]$/.test(t)) return parseInt(t);
  const idMatch = t.match(/^(\d+)$/);
  if (idMatch) return parseInt(idMatch[1]);
  if (t.includes('הסתפרתי') || t.includes('כמה שצריך') || t.includes('10,000') || t.includes('10000') || t.includes('יודעים ותומכים')) return 4;
  if (t.includes('תקופה') || t.includes('עוקב') || t.includes('8-10') || t.includes('7000') || t.includes('7,000') || t.includes('מעל 15') || t.includes('ראיתי הכל') || t.includes('יודעים') || t.includes('שכנוע') || t.includes('ערב')) return 3;
  if (t.includes('מזמן') || t.includes('סרטונים') || t.includes('צפיתי') || t.includes('6-7') || t.includes('4500') || t.includes('4,500') || t.includes('חברים') || t.includes('ראיתי קצת') || t.includes('זרקתי') || t.includes('טלפון') || t.includes('צהריים')) return 2;
  if (t.includes('שמעתי') || t.includes('השבוע') || t.includes('אין לי') || t.includes('3-4') || t.includes('1500') || t.includes('1,500') || t.includes('לא ראיתי') || t.includes('לא סיפרתי') || t.includes('לא היה') || t.includes('זום') || t.includes('בוקר')) return 1;
  return null;
}

// OpenAI rejection classifier
const isRejection = async (text) => {
  if (!text || !text.trim()) return false;
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': 'Bearer OPENAI_API_KEY',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        messages: [
          {
            role: 'system',
            content: 'You classify WhatsApp messages. Does this message express that the person wants to stop, leave, opt out, or is not interested? Reply with only: yes or no'
          },
          { role: 'user', content: text }
        ],
        max_tokens: 5,
        temperature: 0
      })
    });
    const answer = res.choices?.[0]?.message?.content?.trim().toLowerCase();
    return answer === 'yes';
  } catch(e) {
    return false;
  }
};

if (currentState === 'OPTED_OUT') {
  _skip = true;
} else if (currentState === 'DONE_RETRY') {
  const isNeg = await isRejection(message);
  if (isNeg) {
    state = 'OPTED_OUT';
    status = 'opted_out';
    _optedOut = true;
  } else {
    _skip = true;
  }
} else {
  const isNeg = await isRejection(message);
  if (isNeg) {
    state = 'DONE_RETRY';
    responseMsg = 'אתה בטוח?\nזה יקח רק 2 דקות';
  } else switch(currentState) {

    case 'WAIT_CONFIRM': {
      state = 'ASK_AGE';
      responseMsg = 'מעולה! בן כמה אתה?';
      break;
    }

    case 'ASK_AGE': {
      const m = message.match(/\d+/);
      if (!m) { responseMsg = 'לא הצלחתי לזהות גיל 😅 תכתוב לי רק את המספר'; break; }
      const ageVal = parseInt(m[0]);
      answers.age = ageVal;
      age = ageVal;
      if (ageVal <= 11) {
        _disqualified = true;
        responseMsg = 'הבנתי, מצטער אבל הכניסה לאקדמיה היא מגיל 13 ורק חריגים בגיל 12.\nנשמח לשמוע ממך בהמשך :)';
        status = 'disqualified';
        state = 'DISQUALIFIED';
        break;
      }
      if (ageVal === 12) score += 1;
      else if (ageVal <= 14) score += 3;
      else score += 5;
      state = 'ASK_FAMILIARITY';
      contentSid = TEMPLATES['ASK_FAMILIARITY'];
      break;
    }

    case 'ASK_FAMILIARITY': {
      const c = getChoice(msg);
      if (!c) { contentSid = TEMPLATES['ASK_FAMILIARITY']; break; }
      score += {1:0, 2:1, 3:2, 4:4}[c];
      answers.familiarity = c;
      state = 'ASK_EXPERIENCE';
      contentSid = TEMPLATES['ASK_EXPERIENCE'];
      break;
    }

    case 'ASK_EXPERIENCE': {
      const c = getChoice(msg);
      if (!c) { contentSid = TEMPLATES['ASK_EXPERIENCE']; break; }
      answers.experience = c;
      if (c >= 3) has_experience = true;
      state = 'ASK_UNDERSTANDING';
      contentSid = TEMPLATES['ASK_UNDERSTANDING'];
      break;
    }

    case 'ASK_UNDERSTANDING': {
      const c = getChoice(msg);
      if (!c || c > 3) { contentSid = TEMPLATES['ASK_UNDERSTANDING']; break; }
      score += {1:0, 2:0.5, 3:2}[c];
      answers.understanding = c;
      state = 'ASK_HOURS';
      contentSid = TEMPLATES['ASK_HOURS'];
      break;
    }

    case 'ASK_HOURS': {
      const c = getChoice(msg);
      if (!c) { contentSid = TEMPLATES['ASK_HOURS']; break; }
      score += {1:0, 2:1, 3:2, 4:4}[c];
      answers.hours = c;
      state = 'ASK_BUDGET';
      contentSid = TEMPLATES['ASK_BUDGET'];
      break;
    }

    case 'ASK_BUDGET': {
      const c = getChoice(msg);
      if (!c) { contentSid = TEMPLATES['ASK_BUDGET']; break; }
      score += {1:-2, 2:1, 3:2, 4:2}[c];
      answers.budget = c;
      const ageVal = answers.age || 0;
      if (ageVal >= 12 && ageVal <= 18) {
        state = 'ASK_PARENTS';
        contentSid = TEMPLATES['ASK_PARENTS'];
      } else {
        state = 'ASK_MEETING_INTRO';
        contentSid = TEMPLATES['ASK_MEETING_INTRO'];
      }
      break;
    }

    case 'ASK_PARENTS': {
      const c = getChoice(msg);
      if (!c) { contentSid = TEMPLATES['ASK_PARENTS']; break; }
      score += {1:0, 2:0, 3:1, 4:3}[c];
      answers.parents = c;
      state = 'ASK_MEETING_INTRO';
      contentSid = TEMPLATES['ASK_MEETING_INTRO'];
      break;
    }

    case 'ASK_MEETING_INTRO': {
      const c = getChoice(msg);
      if (!c || c > 2) { contentSid = TEMPLATES['ASK_MEETING_INTRO']; break; }
      meeting_type = c === 1 ? 'זום' : 'טלפון';
      answers.meetingType = meeting_type;
      state = 'ASK_AVAILABILITY';
      contentSid = TEMPLATES['ASK_AVAILABILITY'];
      break;
    }

    case 'ASK_AVAILABILITY': {
      const c = getChoice(msg);
      if (!c || c > 3) { contentSid = TEMPLATES['ASK_AVAILABILITY']; break; }
      availability = {1:'בוקר (9-12)', 2:'צהריים (12-16)', 3:'ערב (16-20)'}[c];
      answers.availability = availability;
      lead_type = score >= 16 ? 'hot' : score >= 10 ? 'warm' : 'cold';
      answers.finalScore = score;
      answers.leadType = lead_type;
      state = 'DONE';
      status = 'completed';
      _done = true;
      completed_at = new Date().toISOString();
      responseMsg = 'העברתי אותך לשלב הבא!\nיחזרו אליך לקביעת שיחת התאמה בהקדם האפשרי ובהתאם למקום פנוי🤝';
      break;
    }

    default:
      _skip = true;
  }
}

return {
  json: {
    _skip,
    _disqualified,
    _done,
    _optedOut,
    _responseMsg: responseMsg,
    _contentSid: contentSid,
    phone,
    name: reply.name || session.name || '',
    email: session.email || '',
    state,
    score,
    answers: answers,
    has_experience,
    lead_type,
    status,
    age,
    availability,
    meeting_type,
    completed_at,
    updated_at: new Date().toISOString()
  }
};

const item = $input.item.json;
const phone = item.phone;
const contentSid = item._contentSid;
const body = item._responseMsg || '';

const accountSid = 'TWILIO_ACCOUNT_SID';
const authToken = 'TWILIO_AUTH_TOKEN';

const fromNum = 'whatsapp:+972559398343';
const toNum = 'whatsapp:+' + phone;

let formBody = 'From=' + encodeURIComponent(fromNum) + '&To=' + encodeURIComponent(toNum);

if (contentSid) {
  formBody += '&ContentSid=' + encodeURIComponent(contentSid);
} else {
  formBody += '&Body=' + encodeURIComponent(body);
}

const url = `https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: url,
  headers: {
    'Authorization': 'Basic ' + Buffer.from(accountSid + ':' + authToken).toString('base64'),
    'Content-Type': 'application/x-www-form-urlencoded'
  },
  body: formBody
});

return { json: { ...item, _twilioResponse: response } };

const body = $input.item.json.body || $input.item.json;

let phone = '';
let name = '';
let email = '';

// Twilio WhatsApp format
if (body.WaId || (body.From && body.From.includes('whatsapp:'))) {
  phone = body.WaId || body.From.replace('whatsapp:', '').replace('+', '');
  name = body.ProfileName || 'חבר';
  email = '';
}
// Elementor form format
else if (body['form[id]'] !== undefined || body.form_id !== undefined) {
  for (const key of Object.keys(body)) {
    if (key.includes('[value]')) {
      const val = body[key];
      if (typeof val === 'string' && (val.startsWith('05') || val.startsWith('972') || val.startsWith('+972'))) {
        phone = val;
      }
    }
  }
  name = body['fields[name][value]'] || body['fields[field_name][value]'] || 'חבר';
  email = body['fields[email][value]'] || body['fields[field_email][value]'] || '';
}
// Generic JSON format
else {
  phone = body.phone || body.telephone || body.mobile || body.Phone || body.tel || '';
  name = body.name || body.firstName || body.Name || body.full_name || 'חבר';
  email = body.email || body.Email || '';
}

// Normalize phone
phone = phone.replace(/[^0-9]/g, '');
if (phone.startsWith('0')) phone = '972' + phone.slice(1);
if (!phone.startsWith('972') && phone.length > 0) phone = '972' + phone;

// Validate phone
if (phone.length < 10) {
  const bodyStr = JSON.stringify(body);
  const phoneMatch = bodyStr.match(/0[5][0-9]{8}/);
  if (phoneMatch) {
    phone = '972' + phoneMatch[0].slice(1);
  }
}

return {
  json: {
    _responseMsg: `היי ${name} מה נשמע?\nראיתי שהשארת פרטים לאקדמיה של אלעד רבי, אשמח לשאול אותך כמה שאלות קלילות כדי שאוכל להעביר אותך לשלב הבא של שיחות ההתאמה🤝`,
    phone,
    name,
    email,
    session_id: `${phone}_${Date.now()}`,
    state: 'WAIT_CONFIRM',
    score: 0,
    answers: '{}',
    has_experience: false,
    lead_type: 'pending',
    status: 'in_progress'
  }
};

const src = $('🧠 מנוע שיחה').item.json;
return {
  json: {
    phone: src.phone || '',
    name: src.name || '',
    email: src.email || '',
    state: src.state || '',
    score: src.score || 0,
    answers: src.answers || {},
    has_experience: src.has_experience || false,
    lead_type: src.lead_type || 'pending',
    status: src.status || 'in_progress',
    age: src.age || null,
    availability: src.availability || null,
    meeting_type: src.meeting_type || null,
    completed_at: src.completed_at || null,
    session_id: src.session_id || null,
    updated_at: src.updated_at || new Date().toISOString()
  }
};

